const input = $input.first().json;
const token = input.formQueryParameters?.token;
const apiKey = input['API Key'];

if (!token) throw new Error('No token provided.');
if (!apiKey) throw new Error('No API key provided.');

const baseUrl = '{{SUPABASE_URL}}';
const serviceKey = '{{SUPABASE_SERVICE_KEY}}';
const headers = {
  'apikey': serviceKey,
  'Authorization': 'Bearer ' + serviceKey,
  'Content-Type': 'application/json'
};

// Validate token
const rows = await helpers.httpRequest({
  method: 'GET',
  url: baseUrl + '/rest/v1/credential_tokens?token=eq.' + token + '&select=*',
  headers
});

if (!rows || !Array.isArray(rows) || rows.length === 0) {
  throw new Error('Invalid or unknown token.');
}

const row = rows[0];
if (row.used) throw new Error('This link has already been used.');
if (new Date(row.expires_at) < new Date()) throw new Error('This link has expired.');

// Delete existing credential (if any) then insert new one
await helpers.httpRequest({
  method: 'DELETE',
  url: baseUrl + '/rest/v1/template_credentials?template_id=eq.' + encodeURIComponent(row.template_id) + '&cred_key=eq.' + encodeURIComponent(row.cred_key),
  headers: { ...headers, 'Prefer': 'return=minimal' }
});
await helpers.httpRequest({
  method: 'POST',
  url: baseUrl + '/rest/v1/template_credentials',
  headers: { ...headers, 'Prefer': 'return=minimal' },
  body: {
    template_id: row.template_id,
    cred_key: row.cred_key,
    cred_value: apiKey,
    updated_at: new Date().toISOString()
  }
});

// Mark token as used
await helpers.httpRequest({
  method: 'PATCH',
  url: baseUrl + '/rest/v1/credential_tokens?token=eq.' + token,
  headers: { ...headers, 'Prefer': 'return=minimal' },
  body: { used: true }
});

return [{ json: { success: true } }];
